    // Contadores de errores sintacticos y semanticos
    public int errorCount    = 0;
    public int semErrorCount = 0;

    // Nombre de la funcion que se esta analizando actualmente
    private String currentFunc = "main";

    // ==============================================================
    //  GENERACION DE CODIGO INTERMEDIO
    // ==============================================================

    // Lista de instrucciones generadas
    private List<String> code = new ArrayList<>();

    // Contador de temporales (t1, t2, t3...)
    private int tempCount  = 0;

    // Contador de banderas para los switch (tsw1, tsw2...)
    private int switchFlagCounter = 0;

    // Nombre base del archivo fuente (sin extension)
    public String sourceFileName = "";

    // Genera un nuevo temporal
    private String newTemp() {
        tempCount++;
        return "t" + tempCount;
    }

    // Agrega una instruccion al codigo intermedio
    private void emit(String instruction) {
        code.add(instruction);
    }

    // Construccion de etiquetas de scopes
    private String labelPrefix() {
        return currentFunc;
    }

    private String doPrefix() {
        return labelPrefix() + "_do" + Lexer.doCount;
    }

    private String switchPrefix() {
        return doPrefix() + "_switch" + Lexer.switchCount;
    }

    private String casePrefix() {
        return switchPrefix() + "_case" + Lexer.caseCount;
    }

    private String ifPrefix() {
        return labelPrefix() + "_if" + Lexer.ifCount;
    }

    private String elsePrefix() {
        return labelPrefix() + "_else" + Lexer.elseCount;
    }

    private String endifPrefix() {
        return labelPrefix() + "_endif" + Lexer.ifCount;
    }

    // Escribe todo el codigo intermedio en el archivo _intermediate.txt
    public void writeIntermediateCode() {
        try (PrintWriter pw = new PrintWriter(new FileWriter(sourceFileName + "_intermediate.txt"))) {
            for (String line : code) {
                pw.println(line);
            }
        } catch (IOException e) {
            System.err.println("Error al escribir " + sourceFileName + "_intermediate.txt: " + e.getMessage());
        }
    }

    // ==============================================================
    //  ExprInfo — informacion de cada expresion (tipo, valor constante, direccion)
    // ==============================================================

    static class ExprInfo {
        final String  type;
        final Integer constValue;
        final String  dir;

        ExprInfo(String type) {
            this.type       = type;
            this.constValue = null;
            this.dir        = "_unknown_";
        }

        ExprInfo(String type, Integer constValue) {
            this.type       = type;
            this.constValue = constValue;
            this.dir        = (constValue != null) ? String.valueOf(constValue) : "_unknown_";
        }

        ExprInfo(String type, Integer constValue, String dir) {
            this.type       = type;
            this.constValue = constValue;
            this.dir        = (dir != null) ? dir : "_unknown_";
        }

        ExprInfo(String type, String dir) {
            this.type       = type;
            this.constValue = null;
            this.dir        = (dir != null) ? dir : "_unknown_";
        }

        static ExprInfo error() { return new ExprInfo("error", null, "_error_"); }

        @Override public String toString() {
            return constValue != null
                ? type + "(" + constValue + ")@" + dir
                : type + "@" + dir;
        }
    }

    // ==============================================================
    //  DIMENSIONES DE ARREGLOS
    // ==============================================================

    private Map<String, int[]> arrayDimensions = new HashMap<>();

    private void registerArrayDimensions(String name, int rows, int cols) {
        arrayDimensions.put(name, new int[]{ rows, cols });
    }

    private int[] getArrayDimensions(String name) {
        return arrayDimensions.get(name);
    }

    // Verifica que un indice constante este dentro de los limites del arreglo
    private void checkIndexBound(String arrName, String axisName, int idx, int dim, int line, int col) {
        if (idx < 0 || idx >= dim) {
            semantic_error(line, col,
                "indice de " + axisName + " fuera de limites en arreglo '" + arrName +
                "': indice " + idx + " esta fuera del rango [0.." + (dim - 1) + "]");
        }
    }

    // ==============================================================
    //  TABLA DE FUNCIONES
    // ==============================================================

    private static class FunctionInfo {
        String       returnType;
        List<String> paramTypes = new ArrayList<>();
        List<String> paramNames = new ArrayList<>();

        FunctionInfo(String returnType) { this.returnType = returnType; }

        void addParam(String name, String type) {
            paramNames.add(name);
            paramTypes.add(type);
        }

        @Override public String toString() {
            return returnType + "(" + String.join(", ", paramTypes) + ")";
        }
    }

    private Map<String, FunctionInfo> functionTable  = new HashMap<>();
    private FunctionInfo              currentFuncInfo = null;

    private int paramCounter = 0;

    // ==============================================================
    //  PILA SEMANTICA DE SCOPES
    // ==============================================================

    // Guarda el tipo de una variable y si ya tiene valor asignado
    static class VarInfo {
        final String type;
        boolean initialized;

        VarInfo(String type, boolean initialized) {
            this.type        = type;
            this.initialized = initialized;
        }
    }

    // Pila de bloques activos. Cada bloque tiene sus propias variables.
    // Al entrar a una funcion o if se agrega un nivel, al salir se quita.
    private Deque<Map<String, VarInfo>> semanticStack  = new ArrayDeque<>();
    
    // Nombres de los bloques activos
    private Deque<String>               scopeNames     = new ArrayDeque<>();
    
    // Tipo que debe devolver la funcion actual (null si es main)
    private String                      currentReturnType = null;
    
    // Guarda el tipo de la expresion de cada switch abierto
    private Deque<String>               switchExprTypes   = new ArrayDeque<>();

    // Abre un bloque nuevo y lo agrega a la pila
    private void enterScope(String name) {
        semanticStack.push(new HashMap<>());
        scopeNames.push(name);
    }

    // Cierra el bloque actual y lo elimina de la pila
    private void exitScope() {
        if (!semanticStack.isEmpty()) {
            semanticStack.pop();
            scopeNames.pop();
        }
    }

    // Registra una variable en el bloque actual.
    // Si ya existe en ese mismo bloque, lanza error de duplicado.
    private void declareSymbol(String name, String type, boolean initialized, int line, int col) {
        if (semanticStack.isEmpty()) {
            semantic_error(line, col, "Declaracion fuera de funcion: '" + name + "'");
            return;
        }
        Map<String, VarInfo> current = semanticStack.peek();
        if (current.containsKey(name)) {
            semantic_error(line, col,
                "Variable '" + name + "' ya declarada en este bloque");
        } else {
            current.put(name, new VarInfo(type, initialized));
        }
    }

    // registra la variable sin valor asignado
    private void declareSymbol(String name, String type, int line, int col) {
        declareSymbol(name, type, false, line, col);
    }

    // Marca una variable como inicializada cuando se le asigna un valor
    private void markInitialized(String name) {
        for (Map<String, VarInfo> scope : semanticStack) {
            VarInfo vi = scope.get(name);
            if (vi != null) {
                vi.initialized = true;
                return;
            }
        }
    }

    // Busca el tipo de una variable en la pila sin verificar nada mas.
    // Devuelve null si no la encuentra.
    private String lookupSymbol(String name) {
        for (Map<String, VarInfo> scope : semanticStack) {
            VarInfo vi = scope.get(name);
            if (vi != null) return vi.type;
        }
        return null;
    }

    // Busca la variable y ademas verifica que exista y tenga valor.
    // Si no existe: error "no declarada".
    // Si existe pero no tiene valor: error "sin inicializar".
    private String lookupAndCheckInit(String name, int line, int col) {
        for (Map<String, VarInfo> scope : semanticStack) {
            VarInfo vi = scope.get(name);
            if (vi != null) {
                if (!vi.initialized) {
                    semantic_error(line, col,
                        "Variable '" + name + "' se usa sin haber sido inicializada");
                }
                return vi.type;
            }
        }
        semantic_error(line, col, "Variable '" + name + "' no declarada");
        return null;
    }

    // ==============================================================
    //  FUNCIONES AUXILIARES DE TIPOS
    // ==============================================================

    // Devuelve true si el tipo es int o float
    private boolean isNumeric(String type) {
        return "int".equals(type) || "float".equals(type);
    }

    // Devuelve true si el tipo es un arreglo (contiene "[")
    private boolean isArrayType(String type) {
        return type != null && type.contains("[");
    }

    // Extrae el tipo base de un arreglo. Ejemplo: "int[3][4]" -> "int"
    private String baseType(String type) {
        if (type == null) return null;
        int bracket = type.indexOf('[');
        return bracket >= 0 ? type.substring(0, bracket) : type;
    }

    // Verifica si un valor de un tipo puede asignarse a una variable de otro.
    // int -> float se acepta. Todo lo demas debe ser exactamente igual.
    private boolean isCompatible(String exprType, String varType) {
        if (exprType == null || varType == null) return false;
        if ("error".equals(exprType) || "error".equals(varType)) return true;
        if (exprType.equals(varType)) return true;
        if ("int".equals(exprType) && "float".equals(varType)) return true;
        return false;
    }

    // Calcula el tipo del resultado de una operacion aritmetica.
    // Si alguno es float el resultado es float; si ambos son int es int.
    private String resultType(String t1, String t2) {
        if (t1 == null || t2 == null)             return "error";
        if ("error".equals(t1) || "error".equals(t2)) return "error";
        if ("float".equals(t1) || "float".equals(t2)) return "float";
        if ("int".equals(t1)   && "int".equals(t2))   return "int";
        return "error";
    }

    // Verifica si dos tipos se pueden comparar con equal o n_equal.
    // Acepta mezclas de int y float, y pares del mismo tipo.
    private boolean isEqualityCompatible(String t1, String t2) {
        if (t1 == null || t2 == null) return false;
        if ("error".equals(t1) || "error".equals(t2)) return true;
        if (t1.equals(t2)) return true;
        if (isNumeric(t1) && isNumeric(t2)) return true;
        return false;
    }

    // ==============================================================
    //  ACUMULADOR DE ARGUMENTOS PARA LLAMADAS
    // ==============================================================

    // Guarda el tipo y la direccion de un argumento de una llamada
    private static class ArgInfo {
        final String type;
        final String dir;
        ArgInfo(String type, String dir) { this.type = type; this.dir = dir; }
    }

    // Pila de listas de argumentos. Se usa una pila para soportar
    // llamadas anidadas como f( g(1, 2), 3 ) sin mezclar argumentos.
    private Deque<List<ArgInfo>> argStack = new ArrayDeque<>();

    // Inicia la recoleccion de argumentos para una nueva llamada
    private void beginArgList()                   { argStack.push(new ArrayList<>()); }
    
    // Agrega un argumento a la llamada actual
    private void addArg(String type, String dir)  {
        if (!argStack.isEmpty()) argStack.peek().add(new ArgInfo(type, dir));
    }

    // Termina la recoleccion y devuelve la lista de argumentos
    private List<ArgInfo> endArgList() {
        return argStack.isEmpty() ? Collections.emptyList() : argStack.pop();
    }

    // ==============================================================
    //  VERIFICACIoN DE LLAMADAS A FUNCIoN
    // ==============================================================

    private String checkCall(String funcName, List<ArgInfo> args, int line, int col) {
        FunctionInfo info = functionTable.get(funcName);
        if (info == null) {
            semantic_error(line, col, "Funcion '" + funcName + "' no declarada");
            return "error";
        }
        if (args.size() != info.paramTypes.size()) {
            semantic_error(line, col,
                "Funcion '" + funcName + "' espera " + info.paramTypes.size() +
                " argumento(s), se pasaron " + args.size());
            return info.returnType;
        }
        for (int i = 0; i < args.size(); i++) {
            if (!isCompatible(args.get(i).type, info.paramTypes.get(i))) {
                semantic_error(line, col,
                    "Argumento " + (i + 1) + " de '" + funcName +
                    "': se esperaba " + info.paramTypes.get(i) +
                    " pero se obtuvo " + args.get(i).type);
            }
        }
        return info.returnType;
    }

    // ==============================================================
    //  PILAS DE ETIQUETAS PARA ESTRUCTURAS DE CONTROL
    // ==============================================================

    private Deque<Integer> ifCountStack   = new ArrayDeque<>();
    private Deque<Integer> elseCountStack = new ArrayDeque<>();
    private Deque<Integer> doCountStack   = new ArrayDeque<>();

    private Deque<String>  switchLabelStack   = new ArrayDeque<>();
    private Deque<String>  switchFlagStack    = new ArrayDeque<>();
    private Deque<String>  switchDirStack     = new ArrayDeque<>();
    private Deque<String>  switchExprTypePile = new ArrayDeque<>();

    private Deque<String>  caseLabelStack = new ArrayDeque<>();
    private Deque<Integer> caseNumStack   = new ArrayDeque<>();

    // ==============================================================
    //  MANEJO DE ERRORES
    // ==============================================================

    @Override
    public void syntax_error(Symbol cur_token) {
        errorCount++;
        int    line   = cur_token.left;
        int    column = cur_token.right;
        String lex    = (cur_token.value != null) ? cur_token.value.toString() : "";
        System.err.println("Error sintactico en linea " + line +
                           ", columna " + column +
                           ": token inesperado '" + lex + "'");
    }

    @Override
    public void unrecovered_syntax_error(Symbol cur_token) throws Exception {
        errorCount++;
        int    line   = cur_token.left;
        int    column = cur_token.right;
        String lex    = (cur_token.value != null) ? cur_token.value.toString() : "";
        System.err.println("Error sintactico irrecuperable en linea " + line +
                           ", columna " + column +
                           ": '" + lex + "'. Se detiene el analisis.");
    }

    public void semantic_error(Symbol token, String msg) {
        semErrorCount++;
        int line   = (token != null) ? token.left  : 0;
        int column = (token != null) ? token.right : 0;
        System.err.println("Error semantico en linea " + line +
                           ", columna " + column + ": " + msg);
    }

    public void semantic_error(int line, int col, String msg) {
        semErrorCount++;
        System.err.println("Error semantico en linea " + line +
                           ", columna " + col + ": " + msg);
    }


